#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
    pid_t pid;

    printf("Before fork: Process ID = %d\n", getpid());

    pid = fork();  // Create new process

    if (pid < 0) {
        // Error occurred
        printf("Fork failed!");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child: PID = %d, Parent PID = %d\n", 
               getpid(), getppid());
    }
    else {
        // Parent process
        printf("Parent: PID = %d, Child PID = %d\n", 
               getpid(), pid);
        wait(NULL);  // Wait for child to complete
        printf("Child completed\n");
    }

    return 0;
}
